import{_ as i,c as e,o,ae as a}from"./chunks/framework.CkyPvWOg.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"css/弹性布局(flex).md","filePath":"css/弹性布局(flex).md","lastUpdated":1773308029000}'),r={name:"css/弹性布局(flex).md"};function s(t,l,x,n,f,c){return o(),e("div",null,[...l[0]||(l[0]=[a('<h3 id="_1-flexbox-弹性布局" tabindex="-1">1. Flexbox(弹性布局) <a class="header-anchor" href="#_1-flexbox-弹性布局" aria-label="Permalink to &quot;1. Flexbox(弹性布局)&quot;">​</a></h3><ul><li>弹性布局css3新增的布局方式，用于替代早期的浮动布局和定位布局。</li></ul><h3 id="_2-flex容器属性" tabindex="-1">2. Flex容器属性 <a class="header-anchor" href="#_2-flex容器属性" aria-label="Permalink to &quot;2. Flex容器属性&quot;">​</a></h3><ol><li><code>flex-direction:</code> 决定主轴的方向</li></ol><ul><li>row(默认值): 主轴为水平方向，起点在左端</li><li>row-reverse: 主轴为水平方向，起点在右端</li><li>column: 主轴为垂直方向，起点在上沿</li><li>column-reverse: 主轴为垂直方向，起点在下沿</li><li>注意：主轴和交叉轴是会变化的，由flex-direction决定。</li></ul><ol start="2"><li><code>flex-wrap:</code> 换行</li></ol><ul><li>nowrap(默认值): 不换行</li><li>wrap: 换行，第一行在上方</li><li>wrap-reverse: 换行，第一行在下方</li></ul><ol start="3"><li><code>flex-flow:</code> 是flex-direction和flex-wrap的简写形式</li></ol><ul><li>默认值为row nowrap</li></ul><ol start="4"><li><code>justify-content:</code> 主轴上的对齐方式</li></ol><ul><li>flex-start(默认值): 左对齐</li><li>flex-end: 右对齐</li><li>center: 居中</li><li>space-between: 两端对齐，项目之间的间隔都相等</li><li>space-around: 每个项目两侧的间隔相等，所以项目之间的间隔比项目与边框的间隔大一倍</li><li>space-evenly: 所有项目与项目之间间隔相等，包括项目与边框的间隔</li><li>注意：该项目将等分剩余空间，如果剩余空间为负值，则项目会等比压缩。</li></ul><ol start="5"><li><code>align-items:</code> 交叉轴上的对齐方式</li></ol><ul><li>flex-start: 交叉轴的起点对齐</li><li>flex-end: 交叉轴的终点对齐</li><li>center: 交叉轴的中点对齐</li><li>baseline: 项目的第一行文字的基线对齐</li><li>stretch(默认值): <strong>如果项目未设置高度或设为auto，将占满整个容器的高度</strong></li></ul><ol start="6"><li><code>align-content: </code>多根轴线的对齐方式</li></ol><ul><li>flex-start: 与交叉轴的起点对齐</li><li>flex-end: 与交叉轴的终点对齐</li><li>center: 与交叉轴的中点对齐</li><li>space-between: 与交叉轴两端对齐，轴线之间的间隔平均分布</li><li>space-around: 每根轴线两侧的间隔都相等，所以轴线之间的间隔比轴线与边框的间隔大一倍</li><li>stretch(默认值): 轴线占满整个交叉轴</li></ul><h3 id="_3-flex项目属性" tabindex="-1">3. Flex项目属性 <a class="header-anchor" href="#_3-flex项目属性" aria-label="Permalink to &quot;3. Flex项目属性&quot;">​</a></h3><ol><li><code>order:</code> 定义项目的排列顺序</li></ol><ul><li>数值越小，排列越靠前，默认为0</li></ul><ol start="2"><li><code>flex-grow:</code> 定义项目的放大比例</li></ol><ul><li>默认值为0，即如果存在剩余空间也不放大。</li></ul><ol start="3"><li><code>flex-shrink:</code> 定义了项目的缩小比例</li></ol><ul><li>默认值为1，如果空间不足，该项目将缩小</li></ul><ol start="4"><li><code>flex-basis:</code> 定义了在分配<strong>多余空间之前</strong>，项目占据的主轴空间(main size)</li></ol><ul><li>默认值为auto，即项目的本来大小</li></ul><ol start="5"><li><code>flex:</code> 是flex-grow, flex-shrink 和 flex-basis的简写，默认值为0 1 auto</li><li><code>align-self:</code> 允许单个项目有与其他项目不一样的对齐方式</li></ol><ul><li>该属性可覆盖align-items属性</li><li>默认值为auto，表示继承父元素的align-items属性，如果没有父元素则等同于stretch</li></ul><ol start="7"><li><code>flex:</code> 是一个简写属性，用于同时设置<code>flex-grow</code>, <code>flex-shrink</code> 和 <code>flex-basis</code>。</li></ol><ul><li>注意：在flex属性中，如果只写一个无单位数，那么它表示flex-grow，而flex-shrink为1，flex-basis为0%</li><li>由于flex-basis都是0%，项目初始尺寸为0，所有空间通过flex-grow分配</li></ul><h3 id="_4-flex-grow-flex-shrink-flex-basis的关系" tabindex="-1">4. flex-grow,flex-shrink,flex-basis的关系 <a class="header-anchor" href="#_4-flex-grow-flex-shrink-flex-basis的关系" aria-label="Permalink to &quot;4. flex-grow,flex-shrink,flex-basis的关系&quot;">​</a></h3><ol><li><code>flex-basis:</code></li></ol><ul><li>定义了项目在分配<strong>多余空间之前</strong>的主轴尺寸（main size）。它可以设置为一个长度值（如20%、100px）或关键字（如auto）</li><li>默认值为auto，即项目的本身大小(<strong>由内容或width/height属性决定</strong>)</li></ul><ol start="2"><li><code>flex-grow:</code></li></ol><ul><li>定义了项目的放大比例，决定了当容器有额外空间时，项目应该如何分配这些空间。</li><li>默认值为0，即如果存在剩余空间也不放大。</li></ul><ol start="3"><li><code>flex-shrink:</code></li></ol><ul><li>在主轴上空间不足时，项目应该如何缩减。</li><li>默认值为1，即如果空间不足，该项目将缩小。</li></ul><h3 id="_5-核心计算原理详解" tabindex="-1">5. 核心计算原理详解 <a class="header-anchor" href="#_5-核心计算原理详解" aria-label="Permalink to &quot;5. 核心计算原理详解&quot;">​</a></h3><ol><li>flex-grow 计算（<strong>当有剩余空间时</strong>）</li></ol><ul><li>公式：项目最终宽度 = flex-basis + (项目的flex-grow / 所有项目flex-grow总和) × 剩余空间</li><li>示例：</li></ul><ul><li>容器宽度：600px</li><li>项目flex-basis：100px, 100px, 100px</li><li>项目flex-grow：1, 2, 1</li><li>计算： <ul><li>总基准宽度 = 100 + 100 + 100 = 300px</li><li>剩余空间 = 600 - 300 = 300px</li><li>flex-grow总和 = 1 + 2 + 1 = 4</li><li>每个grow单位分配 = 300px / 4 = 75px</li><li>项目1最终宽度 = 100 + 1×75 = 175px</li><li>项目2最终宽度 = 100 + 2×75 = 250px</li><li>项目3最终宽度 = 100 + 1×75 = 175px</li></ul></li></ul><ol start="2"><li>flex-shrink 计算（<strong>当空间不足时</strong>）</li></ol><ul><li><p>公式：每个项目收缩量 = (每个项目的flex-shrink × 项目的flex-basis / 所有项目的flex-shrink × flex-basis总和) × 超出空间</p><ul><li>计算：</li><li><ol><li>第一步：计算加权因子：每个项目的加权因子 = flex-shrink * flex-basis</li></ol></li><li><ol start="2"><li>第二步：计算所有项目的加权因子之和</li></ol></li><li><ol start="3"><li>第三步：计算每个项目的收缩比例：项目的加权因子 / 加权因子之和</li></ol></li><li><ol start="4"><li>第四步：每个项目的收缩量 = 收缩比例 * 超出空间</li></ol></li></ul></li><li><p>示例：</p><ul><li>容器宽度：400px</li><li>项目flex-basis：150px, 200px, 150px</li><li>项目flex-shrink：1, 2, 1</li><li>总基准宽度 = 150 + 200 + 150 = 500px</li><li>超出空间 = 500 -400 = 100px</li><li>收缩因子总和 = (1×150) + (2×200) + (1×150) = 150 + 400 + 150 = 700</li><li>收缩单位 = 100px / 700 ≈ 0.142857</li><li>项目1收缩量 = 1×150×0.142857 ≈ 21.43px</li><li>项目2收缩量 = 2×200×0.142857 ≈ 57.14px</li><li>项目3收缩量 = 1×150×0.142857 ≈ 21.43px</li><li>项目1最终宽度 = 150 -21.43 ≈ 128.57px</li><li>项目2最终宽度 = 200 -57.14 ≈ 142.86px</li><li>项目3最终宽度 = 150 - 21.43 ≈ 128.57px</li></ul></li></ul><h3 id="特殊情况" tabindex="-1">特殊情况 <a class="header-anchor" href="#特殊情况" aria-label="Permalink to &quot;特殊情况&quot;">​</a></h3><ul><li>flex-grow为0：项目<strong>不参与剩余空间</strong>分配</li><li>flex-shrink为0：项目不收缩，即使<strong>空间不足</strong>也不会缩小</li><li>flex-basis为0%：项目<code>初始尺寸为0</code>，可以认为有剩余空间时，所有空间通过<code>flex-grow</code>分配</li></ul>',43)])])}const h=i(r,[["render",s]]);export{u as __pageData,h as default};
